from cryptography.fernet import Fernet
from configparser import ConfigParser

# Load the key from config
config = ConfigParser()
config.read('app_config.ini')
key = config.get('encryption', 'key')

# Create the cipher
cipher_suite = Fernet(key)

def encrypt_credit_card(card_number):
    return cipher_suite.encrypt(card_number.encode()).decode()

def decrypt_credit_card(encrypted_card_number):
    return cipher_suite.decrypt(encrypted_card_number.encode()).decode()